package main

import (
	"strconv"
)

func isSpecialNumber(num int64) bool {
	s := strconv.FormatInt(num, 10)
	for i := 0; i < len(s)/2; i++ {
		if s[i] != s[len(s)-1-i] {
			return false
		}
	}
	count := make(map[int64]int64)
	for _, ch := range s {
		d := int64(ch - '0')
		if d == 0 {
			return false
		}
		count[d]++
	}
	for d, cnt := range count {
		if cnt != d {
			return false
		}
	}
	return true
}

func solve(n int64) int64 {
	current := n + 1
	for {
		if isSpecialNumber(current) {
			return current
		}
		current++
	}
}
