import math

def is_special_number(num: int) -> bool:
    s = str(num)
    if s != s[::-1]:
        return False
    count = {}
    for ch in s:
        d = int(ch)
        if d == 0:
            return False
        count[d] = count.get(d, 0) + 1
    for d, cnt in count.items():
        if cnt != d:
            return False
    return True

def solve(n: int) -> int:
    current = n + 1
    while True:
        if is_special_number(current):
            return current
        current += 1
